export function tryCatch(r,e,n,...o){try{return n(...o)}catch(n){handleError(n,r,e)}}export function handleError(...r){return errorHandler(...r)}let errorHandler=normalErrorHandler;export function setErrorHandler(r){errorHandler=r}export function normalErrorHandler(r,e,n=void 0){r=Object.assign(r??{message:"No error message given."},{el:e,expression:n}),console.warn(`Alpine Expression Error: ${r.message}\n\n${n?'Expression: "'+n+'"\n\n':""}`,e),setTimeout(()=>{throw r},0)}